SELECT progress_date, progress_value
FROM goal_progress
WHERE progress_id = 0;

SELECT activity_type, target_value
FROM activity_goals
WHERE is_completed = 0;

SELECT distance, start_time, end_time
FROM distance
WHERE activity_id = 0;

SELECT username, first_name, last_name
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM activity_goals
) AND is_active = 1;

SELECT activity_type
FROM activities
WHERE heart_rate_avg = (SELECT MAX(heart_rate_avg) FROM activities);

SELECT activity_id, SUM(calories) AS total_calories_burned
FROM calorie_burn
GROUP BY activity_id;

SELECT duration, heart_rate_avg
FROM activity_levels
WHERE level_type = 'sedentary';

SELECT level_type, AVG(heart_rate_avg) AS average_heart_rate
FROM activity_levels
GROUP BY level_type;
